CREATE TABLE data_type_classifications_metadata ( id serial, data_type_classification_id int4 NOT NULL, key character varying (255) NOT NULL, value character varying (4096),
CONSTRAINT pk_data_type_classifications_metadata PRIMARY KEY (id), CONSTRAINT fk_data_type_classifications_metadata_to_data_type_classifications FOREIGN KEY (data_type_classification_id) REFERENCES data_type_classifications(id) MATCH SIMPLE ON UPDATE NO ACTION ON DELETE NO ACTION );
CREATE INDEX i_data_type_classifications_metadata_data_type_classification_id ON data_type_classifications_metadata USING btree (data_type_classification_id); CREATE UNIQUE INDEX ui_data_type_classifications_metadata_data_type_classification_id_key ON data_type_classifications_metadata (data_type_classification_id, key);
